// ---------- 1. Parse incoming payload robustly ----------
// Frontend sends Content-Type: text/plain to dodge CORS preflight,
// so n8n may hand us a raw string, a Buffer, or an already-parsed object.

function getRawBody() {
  if (Buffer.isBuffer($json.body)) return $json.body.toString('utf-8');
  if (typeof $json.body === 'string') return $json.body;
  if ($json.body && typeof $json.body === 'object') return $json.body;
  if (typeof $json === 'string') return $json;
  if ($json.data) return $json.data;
  return $json;
}

let payload = getRawBody();
if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (e) {
    throw new Error('Could not parse incoming body as JSON: ' + payload.slice(0, 300));
  }
}

const visitsToAdd = payload.visit ? [payload.visit] : (payload.visits || []);
if (!visitsToAdd.length) {
  throw new Error('No visit data. Payload received: ' + JSON.stringify(payload).slice(0, 300));
}

const cleanVisits = visitsToAdd.filter(v => v && typeof v === 'object' && v.id);
if (!cleanVisits.length) {
  throw new Error('Visit entries missing required "id" field.');
}

return [{ json: { visitsToAdd: cleanVisits } }];

// ---------- 2. Merge new visits (dedup by id) ----------
// No GitHub calls here, only pure merge logic.

const visitsToAdd = $('Parse Visit Payload').item.json.visitsToAdd;
const getRes = $json; // output of "Get visits.json" HTTP Request node

const sha = getRes.sha;
let visits = [];
try {
  const decoded = Buffer.from(getRes.content, 'base64').toString('utf-8');
  const parsed = JSON.parse(decoded);
  if (Array.isArray(parsed)) visits = parsed;
} catch (e) {
  throw new Error('Existing visits.json is corrupted - aborting to avoid data loss: ' + e.message);
}

const existingIds = new Set(visits.map(v => v && v.id));
let added = 0;
visitsToAdd.forEach(v => {
  if (v && v.id && !existingIds.has(v.id)) {
    visits.push(v);
    existingIds.add(v.id);
    added++;
  }
});

const raw = JSON.stringify(visits, null, 2);
const contentBase64 = Buffer.from(raw).toString('base64');

return [{
  json: {
    sha,
    contentBase64,
    total: visits.length,
    added,
    skip: added === 0
  }
}];
